// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  const [selectedDay, setSelectedDay] = useState<string>(props.forecast[0]?.day ?? '');
  const [detailsOpen, setDetailsOpen] = useState<boolean>(true);
  const normalizedUnit = props.unit?.trim().toUpperCase() === 'F' ? 'F' : 'C';
  const formattedTemperature = `${props.temperature}°${normalizedUnit}`;
  const conditionLower = props.condition.trim().toLowerCase();
  const weatherIcon = useMemo(() => {
    if (conditionLower.includes('thunder')) return '⛈️';
    if (conditionLower.includes('rain') || conditionLower.includes('drizzle')) return '🌧️';
    if (conditionLower.includes('snow') || conditionLower.includes('sleet')) return '❄️';
    if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
    if (conditionLower.includes('cloud')) return '☁️';
    if (conditionLower.includes('wind')) return '💨';
    if (conditionLower.includes('clear') || conditionLower.includes('sun')) return '☀️';
    return '🌤️';
  }, [conditionLower]);
  const forecastItems = useMemo(() => props.forecast.slice(0, 5).map((item) => ({
    day: item.day ?? '',
    icon: item.icon ?? '',
    high: item.high,
    low: item.low,
  })), [props.forecast]);
  const activeForecast = selectedDay ? forecastItems.find((item) => item.day === selectedDay) ?? forecastItems[0] : forecastItems[0];
  const handleSelectDay = useCallback((day: string) => {
    setSelectedDay(day);
  }, []);
  const handleToggleDetails = useCallback(() => {
    setDetailsOpen((value) => !value);
  }, []);
  return {
    selectedDay,
    setSelectedDay: handleSelectDay,
    detailsOpen,
    setDetailsOpen: handleToggleDetails,
    normalizedUnit,
    formattedTemperature,
    weatherIcon,
    forecastItems,
    activeForecast,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6, 24px)">
      <Card
        padding="var(--ggui-spacing-6, 24px)"
        radius="lg"
        shadow="md"
      >
        <Stack gap="var(--ggui-spacing-6, 24px)">
          <Row align="center">
            <Stack gap="var(--ggui-spacing-1, 4px)" align="start">
              <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Weather</Text>
              <Heading level={2}>{props.city}</Heading>
            </Stack>
            <Spacer size="flex" />
            <Badge variant="primary">{state.normalizedUnit}</Badge>
          </Row>

          <Row align="center">
            <Text size="4xl" weight="bold">{state.formattedTemperature}</Text>
            <Spacer size="flex" />
            <Stack gap="var(--ggui-spacing-1, 4px)" align="start">
              <Text is="span" size="2xl" aria-hidden="true">{state.weatherIcon}</Text>
              <Text variant="bodyLarge" weight="semibold">{props.condition}</Text>
            </Stack>
          </Row>

          <Row wrap align="stretch">
            <Card padding="var(--ggui-spacing-4, 16px)" shadow="none" border>
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                <Text variant="bodyLarge" weight="semibold">{props.humidity}%</Text>
              </Stack>
            </Card>
            <Card padding="var(--ggui-spacing-4, 16px)" shadow="none" border>
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind speed</Text>
                <Text variant="bodyLarge" weight="semibold">{props.windSpeed}</Text>
              </Stack>
            </Card>
          </Row>
          <Divider />
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Row align="center">
              <Heading level={4}>5-day forecast</Heading>
              <Spacer size="flex" />
              <Button variant="ghost" size="sm" onClick={state.setSelectedDay ? () => state.setSelectedDay(state.activeForecast?.day ?? '') : undefined}>
                Focus current
              </Button>
              <Button variant="ghost" size="sm" onClick={state.setDetailsOpen}>
                {state.detailsOpen ? 'Hide details' : 'Show details'}
              </Button>
            </Row>
            <Row gap="var(--ggui-spacing-2, 8px)" wrap>
              {state.forecastItems.map((item) => {
                const isActive = item.day === state.selectedDay;
                return (
                  <Card
                    key={item.day}
                    as={Pressable}
                    onPress={() => state.setSelectedDay(item.day)}
                    padding="var(--ggui-spacing-4, 16px)"
                    shadow={isActive ? 'md' : 'none'}
                    border
                    radius="md"
                  >
                    <Stack gap="var(--ggui-spacing-2, 8px)" align="center">
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{item.day}</Text>
                      <Text is="span" size="2xl" aria-hidden="true">{item.icon}</Text>
                      <Text variant="bodySmall" weight="medium">
                        {item.high != null ? `${item.high}°${state.normalizedUnit}` : '—'} / {item.low != null ? `${item.low}°${state.normalizedUnit}` : '—'}
                      </Text>
                    </Stack>
                  </Card>
                );
              })}
            </Row>
            {state.detailsOpen && state.activeForecast ? (
              <Card padding="var(--ggui-spacing-4, 16px)" shadow="none" border radius="md">
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Selected forecast</Text>
                  <Text variant="bodyLarge" weight="semibold">{state.activeForecast.day}</Text>
                </Stack>
              </Card>
            ) : null}
          </Stack>
        </Card>
      </Container>
        </Card>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touched, setTouched] = useState({ name: false, email: false });
  const [submitted, setSubmitted] = useState(false);

  const safeFeatureOptions = props.featureOptions ?? [];
  const safeSatisfactionLabels = props.satisfactionLabels ?? [];

  const emailValid = /^\S+@\S+\.\S+$/.test(email.trim());
  const nameValid = name.trim().length > 0;
  const satisfactionValid = satisfaction !== '';
  const commentsValue = comments.slice(0, 500);
  const commentsCount = commentsValue.length;

  const nameError = touched.name && !nameValid ? 'Name is required.' : '';
  const emailError = touched.email && !email.trim() ? 'Email is required.' : touched.email && !emailValid ? 'Enter a valid email address.' : '';
  const canGoNextFromStep1 = nameValid && emailValid;
  const canGoNextFromStep2 = satisfactionValid;
  const currentStep = submitted ? 5 : step;
  const progressValue = currentStep;

  const ratingOptions = safeSatisfactionLabels.slice(0, 5).map((label, index) => ({
    value: String(index + 1),
    label,
  }));

  const selectedSatisfactionLabel = ratingOptions.find((option) => option.value === satisfaction)?.label ?? '';

  const featureSummary = features.length ? features : ['None selected'];

  const goNext = useCallback(() => {
    if (step === 1) {
      setTouched({ name: true, email: true });
      if (!canGoNextFromStep1) return;
    }
    if (step === 2 && !canGoNextFromStep2) return;
    setStep((prev) => Math.min(5, prev + 1));
  }, [step, canGoNextFromStep1, canGoNextFromStep2]);

  const goBack = useCallback(() => {
    setStep((prev) => Math.max(1, prev - 1));
  }, []);

  const toggleFeature = useCallback((feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature) ? prev.filter((item) => item !== feature) : [...prev, feature],
    );
  }, []);

  const handleSubmit = useCallback(() => {
    const payload: ActionSubmitPayload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction || 0),
      features,
      comments: commentsValue.trim(),
    };
    setSubmitted(true);
    return payload;
  }, [name, email, satisfaction, features, commentsValue]);

  const reviewItems = [
    { label: 'Name', value: name.trim() || '—' },
    { label: 'Email', value: email.trim() || '—' },
    { label: 'Satisfaction', value: selectedSatisfactionLabel || '—' },
    { label: 'Features', value: featureSummary.join(', ') },
    { label: 'Comments', value: commentsValue.trim() || 'No comments provided.' },
  ];

  return {
    step: currentStep,
    setStep,
    name,
    setName,
    email,
    setEmail,
    satisfaction,
    setSatisfaction,
    features,
    comments: commentsValue,
    setComments,
    touched,
    setTouched,
    submitted,
    emailValid,
    nameValid,
    satisfactionValid,
    commentsCount,
    nameError,
    emailError,
    canGoNextFromStep1,
    canGoNextFromStep2,
    progressValue,
    ratingOptions,
    selectedSatisfactionLabel,
    featureSummary,
    reviewItems,
    safeFeatureOptions,
    goNext,
    goBack,
    toggleFeature,
    handleSubmit,
  };

  const reviewItems = [
    { label: 'Name', value: name.trim() || '—' },
    { label: 'Email', value: email.trim() || '—' },
    { label: 'Satisfaction', value: selectedSatisfactionLabel || '—' },
    { label: 'Features', value: featureSummary.join(', ') },
    { label: 'Comments', value: commentsValue.trim() || 'No comments provided.' },
  ];

  return {
    step: currentStep,
    setStep,
    name,
    setName,
    email,
    setEmail,
    satisfaction,
    setSatisfaction,
    features,
    comments: commentsValue,
    setComments,
    touched,
    setTouched,
    submitted,
    emailValid,
    nameValid,
    satisfactionValid,
    commentsCount,
    nameError,
    emailError,
    canGoNextFromStep1,
    canGoNextFromStep2,
    progressValue,
    ratingOptions,
    selectedSatisfactionLabel,
    featureSummary,
    reviewItems,
    goNext,
    goBack,
    toggleFeature,
    handleSubmit,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row align="center" justify="between">
              <Stack gap="var(--ggui-spacing-1)">
                <Heading level={2}>Multi-step survey</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Step {state.step} of 4
                </Text>
              </Stack>
              <Badge variant={state.step >= 4 ? 'success' : 'primary'}>
                {state.step >= 4 ? 'Review' : 'In progress'}
              </Badge>
            </Row>
            <Progress value={state.progressValue} max={5} showLabel />
          </Stack>
        </Card>

        {state.step === 1 ? (
          <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Your details</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Tell us who you are and how to reach you.
              </Text>
              <Stack gap="var(--ggui-spacing-4)">
                <Input
                  label="Name"
                  required
                  value={state.name}
                  onChange={(value) => state.setName(value)}
                  placeholder="Enter your name"
                  error={state.nameError}
                />
                <Input
                  label="Email"
                  type="email"
                  required
                  value={state.email}
                  onChange={(value) => state.setEmail(value)}
                  placeholder="name@example.com"
                  error={state.emailError}
                />
              </Stack>
            </Stack>
          </Card>
        ) : null}

        {state.step === 2 ? (
          <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Satisfaction rating</Heading>
              <RadioGroup
                label="How satisfied are you?"
                value={state.satisfaction}
                onChange={state.setSatisfaction}
                options={state.ratingOptions}
                direction="vertical"
              />
            </Stack>
          </Card>
        ) : null}

        {state.step === 3 ? (
          <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Feature interests</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select any features you are interested in.
              </Text>
              <Stack gap="var(--ggui-spacing-2)">
                {state.safeFeatureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={state.features.includes(feature)}
                    onChange={() => state.toggleFeature(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        ) : null}

        {state.step === 4 ? (
          <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Comments</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Share any additional thoughts before reviewing your responses.
              </Text>
              <TextArea
                label="Comments"
                value={state.comments}
                onChange={state.setComments}
                placeholder="Share any additional thoughts..."
                maxLength={500}
                showCount
                rows={5}
                helperText={`${state.commentsCount}/500 characters`}
              />
            </Stack>
          </Card>
        ) : null}

        {state.step === 5 ? (
          <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review your answers</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Please confirm everything is correct before submitting.
              </Text>
              <Stack gap="var(--ggui-spacing-3)">
                {state.reviewItems.map((item) => (
                  <Box
                    key={item.label}
                    padding="var(--ggui-spacing-4)"
                    background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                  >
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">{item.label}</Text>
                      <Text>{item.value}</Text>
                    </Stack>
                  </Box>
                ))}
              </Stack>
            </Stack>
          </Card>
        ) : null}

        <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
          <Row align="center" justify="between">
            <Button variant="secondary" onClick={state.goBack} disabled={state.step === 1}>
              Back
            </Button>
            {state.step < 5 ? (
              <Button
                variant="primary"
                onClick={state.goNext}
                disabled={(state.step === 1 && !state.canGoNextFromStep1) || (state.step === 2 && !state.canGoNextFromStep2)}
              >
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={state.handleSubmit}>
                Submit survey
              </Button>
            )}
          </Row>
        </Card>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  const columns = props.columns || [];
  const columnIds = columns.map((column) => column.id || 'todo');
  const [localTasks, setLocalTasks] = useState(() => (props.tasks || []).map((task, index) => ({
    id: task.id || `task-${index}`,
    title: task.title || 'Untitled task',
    priority: task.priority || 'medium',
    assignee: task.assignee || '',
    column: task.column || (columnIds[0] || 'todo'),
    dueDate: task.dueDate || '',
  })));
  const [activeAddColumn, setActiveAddColumn] = useState<string | null>(null);
  const [draftTitle, setDraftTitle] = useState('');
  const [draftPriority, setDraftPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [movingTaskId, setMovingTaskId] = useState<string | null>(null);
  const [streamTaskChanged, setStreamTaskChanged] = useState<StreamTaskChanged | null>(null);

  const taskUpdate = useAction('taskUpdate');

  const normalizeTask = useCallback((task: Props['tasks'][number], index: number = 0) => {
    const fallbackColumn = columnIds[0] || 'todo';
    return {
      id: task.id || `task-${index}`,
      title: task.title || 'Untitled task',
      priority: task.priority || 'medium',
      assignee: task.assignee || '',
      column: task.column || fallbackColumn,
      dueDate: task.dueDate || '',
    };
  }, [columnIds]);

  React.useEffect(() => {
    setLocalTasks((current) => {
      const nextIncoming = (props.tasks || []).map((task, index) => normalizeTask(task, index));
      return nextIncoming.length ? nextIncoming : current;
    });
  }, [normalizeTask, props.tasks]);

  React.useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<StreamTaskChanged>;
      setStreamTaskChanged(customEvent.detail || null);
    };
    if (typeof window !== 'undefined') {
      window.addEventListener('ggui:agent-data', handler);
      return () => window.removeEventListener('ggui:agent-data', handler);
    }
    return undefined;
  }, []);
  React.useEffect(() => {
    if (!streamTaskChanged || !streamTaskChanged.task) return;
    const changed = streamTaskChanged;
    const incoming = normalizeTask(changed.task, Date.now());
    setLocalTasks((current) => {
      if (changed.action === 'delete' && incoming.id) {
        return current.filter((task) => task.id !== incoming.id);
      }
      const existingIndex = current.findIndex((task) => task.id === incoming.id);
      if (existingIndex >= 0) {
        const next = current.slice();
        next[existingIndex] = incoming;
        return next;
      }
      return [incoming, ...current];
    });
  }, [normalizeTask, streamTaskChanged]);

  const tasksByColumn = columns.map((column) => {
    const id = column.id || 'todo';
    return {
      ...column,
      id,
      tasks: localTasks.filter((task) => task.column === id),
    };
  });
  const totalTasks = localTasks.length;
  const doneTasks = localTasks.filter((task) => task.column === 'done').length;
  const priorityVariant = useCallback((priority?: 'low' | 'medium' | 'high') => {
    if (priority === 'high') return 'error';
    if (priority === 'medium') return 'warning';
    return 'success';
  }, []);
  const moveTask = useCallback((taskId: string, column: string) => {
    setLocalTasks((current) => current.map((task) => task.id === taskId ? { ...task, column } : task));
    taskUpdate({ action: 'move', taskId, data: { column } });
  }, [taskUpdate]);
  const startEdit = useCallback((taskId: string, title: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(title);
  }, []);
  const saveEdit = useCallback((taskId: string) => {
    const nextTitle = editingTitle.trim();
    if (!nextTitle) return;
    const editedTask = localTasks.find((task) => task.id === taskId);
    const nextColumn = editedTask?.column || 'todo';
    setLocalTasks((current) => current.map((task) => task.id === taskId ? { ...task, title: nextTitle } : task));
    setEditingTaskId(null);
    setEditingTitle('');
    taskUpdate({ action: 'edit', taskId, data: { column: nextColumn } });
  }, [editingTitle, localTasks, taskUpdate]);
  const beginAddTask = useCallback((columnId: string) => {
    setActiveAddColumn(columnId);
    setDraftTitle('');
    setDraftPriority('medium');
  }, []);
  const createTask = useCallback((columnId: string) => {
    const title = draftTitle.trim();
    if (!title) return;
    const newTask = {
      id: `task-${Date.now()}`,
      title,
      priority: draftPriority,
      assignee: '',
      column: 'todo',
      dueDate: '',
    };
    setLocalTasks((current) => [newTask, ...current]);
    setActiveAddColumn(null);
    setDraftTitle('');
    setDraftPriority('medium');
    taskUpdate({ action: 'create', taskId: newTask.id, data: { column: 'todo' } });
  }, [draftPriority, draftTitle, taskUpdate]);
  const assigneeInitials = useCallback((assignee: string) => {
    const trimmed = assignee.trim();
    if (!trimmed) return '??';
    return trimmed.split(/\s+/).slice(0, 2).map((part) => part.charAt(0)).join('').toUpperCase();
  }, []);
