// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const categoryTokens = useMemo(() => ({
    actinide: { background: 'var(--ggui-color-error-50, #fef2f2)', color: 'var(--ggui-color-error-800, #991b1b)', border: 'var(--ggui-color-error-200, #fecaca)' },
    alkaliMetal: { background: 'var(--ggui-color-warning-50, #fffbeb)', color: 'var(--ggui-color-warning-800, #92400e)', border: 'var(--ggui-color-warning-200, #fde68a)' },
    alkalineEarthMetal: { background: 'var(--ggui-color-warning-100, #fef3c7)', color: 'var(--ggui-color-warning-800, #92400e)', border: 'var(--ggui-color-warning-200, #fde68a)' },
    halogen: { background: 'var(--ggui-color-primary-100, #e0f2fe)', color: 'var(--ggui-color-primary-800, #075985)', border: 'var(--ggui-color-primary-200, #bae6fd)' },
    lanthanide: { background: 'var(--ggui-color-info-50, #ecfeff)', color: 'var(--ggui-color-info-800, #155e75)', border: 'var(--ggui-color-info-200, #a5f3fc)' },
    metalloid: { background: 'var(--ggui-color-success-50, #f0fdf4)', color: 'var(--ggui-color-success-800, #166534)', border: 'var(--ggui-color-success-200, #bbf7d0)' },
    nobleGas: { background: 'var(--ggui-color-primary-50, #f0f9ff)', color: 'var(--ggui-color-primary-900, #0c4a6e)', border: 'var(--ggui-color-primary-200, #bae6fd)' },
    nonmetal: { background: 'var(--ggui-color-success-100, #dcfce7)', color: 'var(--ggui-color-success-800, #166534)', border: 'var(--ggui-color-success-200, #bbf7d0)' },
    postTransitionMetal: { background: 'var(--ggui-color-surfaceVariant, #f4f4f5)', color: 'var(--ggui-color-onSurfaceVariant, #52525b)', border: 'var(--ggui-color-outlineVariant, #e4e4e7)' },
    transitionMetal: { background: 'var(--ggui-color-primary-100, #e0f2fe)', color: 'var(--ggui-color-primary-900, #0c4a6e)', border: 'var(--ggui-color-primary-300, #7dd3fc)' },
    unknown: { background: 'var(--ggui-color-surfaceVariant, #f4f4f5)', color: 'var(--ggui-color-onSurfaceVariant, #52525b)', border: 'var(--ggui-color-outline, #d4d4d8)' },
  }), []);

  const normalizedElements = useMemo(() => {
    return [...props.elements]
      .sort((a, b) => {
        const aRow = typeof a.row === 'number' ? a.row : Number.POSITIVE_INFINITY;
        const bRow = typeof b.row === 'number' ? b.row : Number.POSITIVE_INFINITY;
        if (aRow !== bRow) return aRow - bRow;
        const aCol = typeof a.col === 'number' ? a.col : Number.POSITIVE_INFINITY;
        const bCol = typeof b.col === 'number' ? b.col : Number.POSITIVE_INFINITY;
        if (aCol !== bCol) return aCol - bCol;
        return (a.atomicNumber ?? 0) - (b.atomicNumber ?? 0);
      });
  }, [props.elements]);

  const normalize = useCallback((value?: string) => (value || '').toLowerCase(), []);

  const filteredElements = useMemo(() => {
    const query = searchQuery.trim().toLowerCase();
    return normalizedElements.filter((element) => {
      if (!query) return true;
      return normalize(element.name).includes(query) || normalize(element.symbol).includes(query);
    });
  }, [normalize, normalizedElements, searchQuery]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber == null) return undefined;
    return props.elements.find((element) => element.atomicNumber === selectedAtomicNumber);
  }, [props.elements, selectedAtomicNumber]);

  const visibleElementIds = useMemo(() => new Set(filteredElements.map((element) => element.atomicNumber)), [filteredElements]);

  const legendCategories = useMemo(() => {
    const seen = new Set<string>();
    return normalizedElements
      .map((element) => element.category || 'unknown')
      .filter((category) => {
        if (seen.has(category)) return false;
        seen.add(category);
        return true;
      });
  }, [normalizedElements]);

  const getToken = useCallback((category?: string) => {
    const key = (category || 'unknown') as keyof typeof categoryTokens;
    return categoryTokens[key] || categoryTokens.unknown;
  }, [categoryTokens]);

  const handleElementSelect = useCallback((atomicNumber?: number) => {
    if (typeof atomicNumber !== 'number') return;
    setSelectedAtomicNumber(atomicNumber);
  }, []);

  const getGridStyle = useCallback((element: Props['elements'][number]) => ({
    gridRow: element.row == null ? undefined : String(element.row),
    gridColumn: element.col == null ? undefined : String(element.col),
  }), []);

  return {
    searchQuery,
    setSearchQuery,
    selectedAtomicNumber,
    selectedElement,
    filteredElements,
    visibleElementIds,
    legendCategories,
    getToken,
    handleElementSelect,
    getGridStyle,
  };
}

