/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };

function useComponent(props: Props) {
  const [activeTab, setActiveTab] = useState('description');
  const [quantity, setQuantity] = useState(1);
  const productId = props.product.id ?? '';
  const maxStock = Math.max(1, props.product.stock ?? 1);
  const currentQuantity = Math.min(Math.max(quantity, 1), maxStock);
  const currency = props.product.currency ?? '';
  const priceValue = props.product.price ?? 0;
  const ratingValue = Math.max(0, Math.min(5, Math.round(props.product.rating ?? 0)));
  const stockCount = props.product.stock ?? 0;
  const isInStock = stockCount > 0;
  const stockBadgeVariant = stockCount > 5 ? 'success' : 'warning';
  const handleQuantityChange = useCallback((nextValue: number) => {
    setQuantity(Math.min(Math.max(nextValue, 1), maxStock));
  }, [maxStock]);
  const handleAddToCart = useCallback(() => {
    if (!productId || !isInStock) return;
    (props as unknown as { onAddToCart?: (payload: { productId: string; quantity: number }) => void }).onAddToCart?.({ productId, quantity: currentQuantity });
  }, [currentQuantity, isInStock, productId, props]);
  return {
    activeTab,
    setActiveTab,
    quantity: currentQuantity,
    handleQuantityChange,
    handleAddToCart,
    productId,
    currency,
    priceValue,
    ratingValue,
    stockCount,
    isInStock,
    stockBadgeVariant,
  };
}

