function useComponent(props: Props) {
  const [draft, setDraft] = useState('');
  const [localMessages, setLocalMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages || []);
  const [typingActive, setTypingActive] = useState(false);
  const [typingSender, setTypingSender] = useState<string | undefined>(undefined);
  const messageEndRef = useRef<HTMLDivElement | null>(null);

  const formatTimestamp = useCallback((value?: string) => {
    if (!value) return '';
    const parsed = new Date(value);
    if (Number.isNaN(parsed.getTime())) return value;
    return parsed.toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' });
  }, []);

  const appendMessage = useCallback((next: { sender?: string; text?: string; timestamp?: string }) => {
    setLocalMessages((current) => [...current, next]);
  }, []);

  const handleSend = useCallback(() => {
    const text = draft.trim();
    if (!text) return;
    const timestamp = new Date().toISOString();
    appendMessage({ sender: props.currentUser, text, timestamp });
    props.sendMessage({ text, timestamp });
    setDraft('');
  }, [appendMessage, draft, props.currentUser, props.sendMessage]);

  const handleDraftChange = useCallback((value: unknown) => {
    const nextValue = typeof value === 'string' ? value : String((value as { target?: { value?: string } })?.target?.value ?? '');
    setDraft(nextValue);
  }, []);

  const handleKeyDown = useCallback((event: React.KeyboardEvent<HTMLInputElement>) => {
    if (event.key === 'Enter' && !event.shiftKey) {
      event.preventDefault();
      handleSend();
    }
  }, [handleSend]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent;
      const payload = customEvent.detail;
      if (!payload) return;
      const incomingMessage: StreamMessage | undefined =
        payload.type === 'message'
          ? (payload.data as StreamMessage)
          : (payload as StreamMessage);
      if (incomingMessage) {
        appendMessage(incomingMessage);
      }
      const typingPayload: StreamTyping | undefined =
        payload.type === 'typing'
          ? (payload.data as StreamTyping)
          : (payload as StreamTyping);
      if (typingPayload) {
        setTypingActive(Boolean(typingPayload.active));
        setTypingSender(typingPayload.active ? typingPayload.sender : undefined);
      }
    };
    window.addEventListener('message', handler);
    return () => window.removeEventListener('message', handler);
  }, [appendMessage]);

  useEffect(() => {
    messageEndRef.current?.scrollIntoView({ behavior: 'smooth', block: 'end' });
  }, [localMessages, typingActive]);

  useEffect(() => {
    setLocalMessages(props.messages || []);
  }, [props.messages]);

  const groupedMessages = localMessages.map((entry, index) => {
    const prev = localMessages[index - 1];
    const next = localMessages[index + 1];
    const groupStart = index === 0 || prev?.sender !== entry.sender;
    const groupEnd = index === localMessages.length - 1 || next?.sender !== entry.sender;
    return {
      ...entry,
      isCurrentUser: entry.sender === props.currentUser,
      groupStart,
      groupEnd,
      showSender: groupStart,
      showTimestamp: groupEnd,
    };
  });

  return {
    draft,
    setDraft: handleDraftChange,
    handleSend,
    handleKeyDown,
    messageEndRef,
    groupedMessages,
    formatTimestamp,
    participantCount: props.participantCount,
    title: props.title,
    currentUser: props.currentUser,
    typingActive,
    typingSender,
  };
}

