// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };

function useComponent(props: Props) {
  const [currentTime, setCurrentTime] = useState(() => new Date());
  const [stocks, setStocks] = useState(() => props.stocks ?? []);
  const [updatedSymbols, setUpdatedSymbols] = useState<Record<string, number>>({});
  const [marketState, setMarketState] = useState<string | null>(null);
  const [marketTimestamp, setMarketTimestamp] = useState<string>('');
  const [flashSequence, setFlashSequence] = useState(0);
  const [flashExpiry, setFlashExpiry] = useState<Record<string, number>>({});

  useEffect(() => {
    setStocks(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (typeof window === 'undefined') return;

    const handler = (event: Event) => {
      const customEvent = event as CustomEvent;
      const detail = customEvent.detail as {
        type?: string;
        symbol?: string;
        price?: number;
        change?: number;
        changePercent?: number;
        status?: 'open' | 'closed' | 'pre-market' | 'after-hours';
        timestamp?: string;
      } | undefined;

      if (!detail) return;

      if (detail.type === 'priceUpdate' && detail.symbol) {
        setStocks((current) =>
          (current ?? []).map((stock) =>
            stock.symbol === detail.symbol
              ? {
                  ...stock,
                  price: typeof detail.price === 'number' ? detail.price : typeof stock.price === 'number' ? stock.price : 0,
                  change: typeof detail.change === 'number' ? detail.change : typeof stock.change === 'number' ? stock.change : 0,
                  changePercent: typeof detail.changePercent === 'number' ? detail.changePercent : typeof stock.changePercent === 'number' ? stock.changePercent : 0,
                }
              : stock,
          ),
        );
        setUpdatedSymbols((current) => ({ ...current, [detail.symbol as string]: Date.now() }));
        setFlashSequence((current) => current + 1);
        setFlashExpiry((current) => ({ ...current, [detail.symbol as string]: Date.now() + 1200 }));
      }
      if (detail.type === 'marketStatus' && detail.status) {
        setMarketState(detail.status);
        setMarketTimestamp(detail.timestamp ?? new Date().toISOString());
      }
    };

    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, []);

  useEffect(() => {
    if (typeof window === 'undefined') return;
    const cleanup = window.setInterval(() => {
      const now = Date.now();
      setUpdatedSymbols((current) => {
        const next: Record<string, number> = {};
        Object.entries(current).forEach(([symbol, time]) => {
          if (now - time < 1200) next[symbol] = time;
        });
        return next;
      });
      setFlashExpiry((current) => {
        const next: Record<string, number> = {};
        Object.entries(current).forEach(([symbol, expiry]) => {
          if (now < expiry) next[symbol] = expiry;
        });
        return next;
      });
    }, 150);
    return () => clearInterval(cleanup);
  }, []);

  const mergedStocks = (stocks ?? []).map((stock) => {
    const symbol = stock.symbol ?? '';
    const flashKey = updatedSymbols[symbol];
    return {
      symbol,
      name: stock.name ?? '',
      price: typeof stock.price === 'number' ? stock.price : 0,
      change: typeof stock.change === 'number' ? stock.change : 0,
      changePercent: typeof stock.changePercent === 'number' ? stock.changePercent : 0,
      isPositive: (typeof stock.change === 'number' ? stock.change : 0) >= 0,
      flashKey,
      flashing: !!flashKey && (flashExpiry[symbol] ?? 0) > Date.now(),
    };
  });

  const marketStatusLabel = marketState ? marketState.replace(/-/g, ' ') : 'live';
  const marketStatusTimestampLabel = marketTimestamp ? new Date(marketTimestamp).toLocaleString() : currentTime.toLocaleString();
  const lastUpdatedLabel = marketTimestamp ? new Date(marketTimestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' }) : currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });

  return {
    currentTime,
    mergedStocks,
    marketState,
    marketTimestamp,
    marketStatusLabel,
    marketStatusTimestampLabel,
    lastUpdatedLabel,
    flashSequence,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
