import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };

function useComponent(props: Props) {
  const complete = useCallback((payload: ActionCompletePayload) => {
    // onComplete is not part of Props in this contract; expose the payload via complete() only.
    return payload;
  }, []);

  const [name, setName] = useState(props.initialProfile.name ?? '');
  const [email, setEmail] = useState(props.initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar ?? '');
  const [role, setRole] = useState(props.initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme ?? 'light');
  const [step, setStep] = useState(1);
  const [touched, setTouched] = useState(false);

  const emailError = email.trim().length > 0 && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()) ? 'Enter a valid email address.' : '';
  const nameError = touched && !name.trim() ? 'Name is required.' : '';
  const isStep1Valid = name.trim().length > 0 && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim());
  const isStep2Valid = Boolean(role);
  const isLastStep = step === 3;
  const canGoNext = step === 1 ? isStep1Valid : step === 2 ? isStep2Valid : true;

  const avatarOptions = props.avatarOptions && props.avatarOptions.length > 0 ? props.avatarOptions : ['🙂', '😎', '🤖', '🌟'];
  const roleOptions = props.roleOptions && props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other'];

  const handleGoToStep = useCallback((targetStep: number) => {
    if (targetStep < 1 || targetStep > 3) return;
    if (targetStep > 1 && !isStep1Valid) return;
    if (targetStep > 2 && !isStep2Valid) return;
    setStep(targetStep);
  }, [isStep1Valid, isStep2Valid]);

  const handleNext = useCallback(() => {
    setTouched(true);
    if (step === 1) {
      if (!isStep1Valid) return;
      setStep(2);
      return;
    }
    if (step === 2) {
      if (!isStep2Valid) return;
      setStep(3);
    }
  }, [isStep1Valid, isStep2Valid, step]);

  const handleBack = useCallback(() => {
    setStep((current) => Math.max(1, current - 1));
  }, []);

  const handleComplete = useCallback(() => {
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar: avatar || avatarOptions[0] || '🙂',
      role: role,
      emailNotifications,
      theme,
    };
    complete(payload);
  }, [avatar, avatarOptions, complete, email, emailNotifications, name, role, theme]);

  return {
    name, setName,
    email, setEmail,
    avatar, setAvatar,
    role, setRole,
    emailNotifications, setEmailNotifications,
    theme, setTheme,
    step, setStep,
    touched, setTouched,
    emailError,
    nameError,
    isStep1Valid,
    isStep2Valid,
    isLastStep,
    canGoNext,
    avatarOptions,
    roleOptions,
    handleGoToStep,
    handleNext,
    handleBack,
    handleComplete,
    complete,
  };
}



