                  <Heading level={3}>Profile Setup</Heading>
                  <Input label="Name" required value={state.name} onChange={state.setName} error={state.nameError} helperText="Enter your full name." />
                  <Input label="Email" type="email" required value={state.email} onChange={state.setEmail} error={state.emailError} helperText="We will use this to contact you." />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text is="label" variant="label">Avatar selection</Text>
                    <Row gap="var(--ggui-spacing-2)" wrap>
                      {state.avatarOptions.map((item) => (
                        <Card
                          key={item}
                          as={Clickable}
                          onClick={() => state.setAvatar(item)}
                          padding="var(--ggui-spacing-2)"
                          radius="md"
                          shadow={state.avatar === item ? 'md' : 'sm'}
                          border
                          hoverStyle={{ opacity: 0.85 }}
                          style={{
                            background: state.avatar === item ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                            borderColor: state.avatar === item ? 'var(--ggui-color-primary-300)' : 'var(--ggui-color-outlineVariant)',
                            minWidth: 'var(--ggui-spacing-12)',
                            textAlign: 'center',
                          }}
                        >
                          <Stack gap="var(--ggui-spacing-1)" align="center">
                            <Text variant="bodyLarge" as="span">{item}</Text>
                          </Stack>
                        </Card>
                      ))}
                    </Row>
                  </Stack>
                </Stack>
              </Box>

              <Box
                style={{
                  opacity: state.step === 2 ? 1 : 0,
                  transform: state.step === 2 ? 'translateX(0)' : 'translateX(1rem)',
                  transition: 'opacity 200ms ease-in-out, transform 200ms ease-in-out',
                  position: state.step === 2 ? 'relative' : 'absolute',
                  inset: 0,
                  pointerEvents: state.step === 2 ? 'auto' : 'none',
                }}
              >
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={3}>Preferences</Heading>
                  <Select
                    label="Role"
                    required
                    value={state.role}
                    onChange={state.setRole}
                    options={state.roleOptions.map((option) => ({ value: option, label: option }))}
                    placeholder="Select your role"
                    helperText="Choose the role that best describes you."
                  />
                  <Checkbox
                    label="Email notifications"
                    checked={state.emailNotifications}
                    onChange={state.setEmailNotifications}
                    description="Receive product updates and important alerts by email."
                  />
                  <Toggle
                    label={state.theme === 'dark' ? 'Dark theme' : 'Light theme'}
                    checked={state.theme === 'dark'}
                    onChange={(checked) => state.setTheme(checked ? 'dark' : 'light')}
                  />
                </Stack>
              </Box>

              <Box
                style={{
                  opacity: state.step === 3 ? 1 : 0,
                  transform: state.step === 3 ? 'translateX(0)' : 'translateX(1rem)',
                  transition: 'opacity 200ms ease-in-out, transform 200ms ease-in-out',
                  position: state.step === 3 ? 'relative' : 'absolute',
                  inset: 0,
                  pointerEvents: state.step === 3 ? 'auto' : 'none',
                }}
              >
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={3}>Review & Confirm</Heading>
                  <Card padding="var(--ggui-spacing-4)" radius="md" border shadow="none">
                    <Stack gap="var(--ggui-spacing-3)">
                      {summaryItems.map((item) => (
                        <Row key={item.label} justify="between" gap="var(--ggui-spacing-4)">
                          <Text variant="label">{item.label}</Text>
                          <Text variant="bodySmall" align="right">{item.value}</Text>
                        </Row>
                      ))}
                    </Stack>
                  </Card>
                  <Alert variant="info" title="Ready to finish">Review the details above, then complete setup.</Alert>
                </Stack>
              </Box>
            </Box>

            <Divider />

            <Row justify="between" align="center" wrap>
              {state.step === 3 ? (
                <Button variant="ghost" onClick={state.handleBack}>Go Back</Button>
              ) : (
                <Button variant="ghost" onClick={state.handleBack} disabled={state.step === 1}>Back</Button>
              )}
              <Spacer size="flex" />
              {state.step < 3 ? (
                <Button variant="primary" onClick={state.handleNext} disabled={!state.canGoNext}>Next</Button>
              ) : (
                <Button variant="primary" onClick={state.handleComplete} disabled={!state.isStep1Valid || !state.isStep2Valid}>Complete Setup</Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );

}
